    /**
     * Return the path tuple for a roundabout. Buckets the exit angle to the nearest
     * 10° (36-way) — the white exit arrow is a continuous MapKit core-primitive render
     * at that angle (finer than Apple's own 8-way card snap), while the grey ring+spokes
     * background is the nearest 45° slot. Returns null if the (nArms, exitOrdinal)
     * combination has no extracted path (some edge cases failed `MKJunction init`).
     */
    internal fun roundaboutPaths(nArms: Int, exitOrdinal: Int, relExitDeg: Double): RoundaboutPaths? {
        val clampedArms = nArms.coerceIn(2, 5)
        val clampedOrd  = exitOrdinal.coerceIn(1, clampedArms - 1)
        val normDeg = ((relExitDeg % 360) + 360 + 180) % 360 - 180  // -180..+180
        val bucket = (Math.round((normDeg + 180.0) / 10.0).toInt()) % 36
        return roundaboutMap[RoundaboutKey(clampedArms, clampedOrd, bucket)]
            ?: roundaboutMap[RoundaboutKey(clampedArms, clampedOrd, (bucket + 1) % 36)]
            ?: roundaboutMap[RoundaboutKey(clampedArms, clampedOrd, (bucket + 35) % 36)]
    }
}